 1	import type { FC } from 'react';
 2	import { Controller, useWatch } from 'react-hook-form';
 3	import EmptyCategorySelectOption from 'src/plans/components/EmptyCategorySelectOption';
 4	
 5	import Select from '@components/common/Select';
 6	import { SelectGroup, SelectList, SelectOption } from '@patternfly/react-core';
 7	import { isEmpty } from '@utils/helpers';
 8	import { useForkliftTranslation } from '@utils/i18n';
 9	
10	import { useCreatePlanFormContext } from '../../hooks/useCreatePlanFormContext';
11	import type { MappingValue } from '../../types';
12	
13	import { NetworkMapFieldId, type NetworkMapping } from './constants';
14	
15	type SourceNetworkFieldProps = {
16	  fieldId: string;
17	  usedSourceNetworks: MappingValue[];
18	  otherSourceNetworks: MappingValue[];
19	};
20	
21	const SourceNetworkField: FC<SourceNetworkFieldProps> = ({
22	  fieldId,
23	  otherSourceNetworks,
24	  usedSourceNetworks,
25	}) => {
26	  const { t } = useForkliftTranslation();
27	  const { control, trigger } = useCreatePlanFormContext();
28	  const networkMappings = useWatch({ control, name: NetworkMapFieldId.NetworkMap });
29	
30	  return (
31	    <Controller
32	      name={fieldId}
33	      control={control}
34	      render={({ field }) => (
35	        <Select
36	          ref={field.ref}
37	          id={fieldId}
38	          value={(field.value as MappingValue).name}
39	          onSelect={async (_event, value) => {
40	            field.onChange(value);
41	            await trigger(NetworkMapFieldId.NetworkMap);
42	          }}
43	          placeholder={t('Select source network')}
44	        >
45	          <SelectGroup label={t('Networks used by the selected VMs')}>
46	            <SelectList>
47	              {isEmpty(usedSourceNetworks) ? (
48	                <EmptyCategorySelectOption resourceName="networks" />
49	              ) : (
50	                usedSourceNetworks.map((usedNetwork) => (
51	                  <SelectOption
52	                    key={usedNetwork.name}
53	                    value={usedNetwork}
54	                    isDisabled={networkMappings.some(
55	                      (mapping: NetworkMapping) =>
56	                        mapping[NetworkMapFieldId.SourceNetwork].name === usedNetwork.name,
57	                    )}
58	                  >
59	                    {usedNetwork.name}
60	                  </SelectOption>
61	                ))
62	              )}
63	            </SelectList>
64	          </SelectGroup>
65	
66	          <SelectGroup label={t('Other networks present on the source provider')}>
67	            <SelectList>
68	              {isEmpty(otherSourceNetworks) ? (
69	                <EmptyCategorySelectOption resourceName="networks" />
70	              ) : (
71	                otherSourceNetworks?.map((otherNetwork) => (
72	                  <SelectOption
73	                    key={otherNetwork.name}
74	                    value={otherNetwork}
75	                    isDisabled={networkMappings.some(
76	                      (mapping: NetworkMapping) =>
77	                        mapping[NetworkMapFieldId.SourceNetwork].name === otherNetwork.name,
78	                    )}
79	                  >
80	                    {otherNetwork.name}
81	                  </SelectOption>
82	                ))
83	              )}
84	            </SelectList>
85	          </SelectGroup>
86	        </Select>
87	      )}
88	    />
89	  );
90	};
91	
92	export default SourceNetworkField;

